394: type webhookAnnotator struct {
395: 	attr                    *admission.VersionedAttributes
396: 	failedOpenAnnotationKey string
397: 	patchAnnotationKey      string
398: 	mutationAnnotationKey   string
399: 	webhook                 string
400: 	configuration           string
401: }
